# Custom Theme System – Implementation Plan

## Context

T3 Code's existing `useTheme` hook supports only a light/dark/system color-scheme toggle (stored as
`"light" | "dark" | "system"` in localStorage). The task is to replace that with a richer *named-theme*
system: full `Theme` objects with per-surface color tokens, font settings, and a preview UI. The work
spans three packages: `packages/shared` (new theme definitions), `apps/web/src/hooks` (new hook), and
`apps/web/src/components` (new `ThemeSelector` + sidebar/settings wiring).

No new dependencies. No build-config changes.

---

## Files to Create or Modify

| File | Action |
|------|--------|
| `packages/shared/src/themes.ts` | **Create** – Theme types + built-in data |
| `packages/shared/package.json` | **Modify** – add `./themes` subpath export |
| `apps/web/src/hooks/useTheme.ts` | **Replace** – new Theme-object-based hook |
| `apps/web/src/components/ThemeSelector.tsx` | **Create** – dropdown with swatches |
| `apps/web/src/routes/_chat.settings.tsx` | **Modify** – update Appearance section |
| `apps/web/src/components/Sidebar.tsx` | **Modify** – add ThemeSelector to footer |

---

## Step 1 – `packages/shared/src/themes.ts`

No Effect, no external deps. Pure TypeScript.

```ts
export interface ThemeColors {
  readonly background: string;   // CSS color value applied to --background
  readonly foreground: string;   // applied to --foreground
  readonly accent: string;       // applied to --accent (hover/subtle bg) and --primary
  readonly sidebar: string;      // applied to --sidebar-bg (new variable)
  readonly editor: string;       // applied to --editor-bg (new variable)
  readonly terminal: string;     // applied to --terminal-bg (new variable)
  readonly statusBar: string;    // applied to --status-bar-bg (new variable)
}

export interface Theme {
  readonly id: string;
  readonly name: string;
  readonly colorScheme: "light" | "dark";   // drives the .dark CSS class
  readonly colors: ThemeColors;
  readonly fontFamily: string;              // applied to --font-sans
  readonly fontSize: number;               // px, applied to --base-font-size
}

export const DEFAULT_THEME_ID = "t3-dark";

// t3-dark – default dark theme matching current dark Tailwind variables
const T3_DARK: Theme = { id: "t3-dark", name: "T3 Dark", colorScheme: "dark", colors: {
  background: "#0a0a0a", foreground: "#f5f5f5", accent: "#171717",
  sidebar: "#111111", editor: "#141414", terminal: "#000000", statusBar: "#1a1a1a",
}, fontFamily: "DM Sans, sans-serif", fontSize: 14 };

// t3-light – light theme matching current light Tailwind variables
const T3_LIGHT: Theme = { id: "t3-light", name: "T3 Light", colorScheme: "light", colors: {
  background: "#ffffff", foreground: "#262626", accent: "#f5f5f5",
  sidebar: "#f9fafb", editor: "#ffffff", terminal: "#1a1a1a", statusBar: "#e5e7eb",
}, fontFamily: "DM Sans, sans-serif", fontSize: 14 };

// t3-midnight – a blue-tinted ultra-dark variant
const T3_MIDNIGHT: Theme = { id: "t3-midnight", name: "T3 Midnight", colorScheme: "dark", colors: {
  background: "#0d0f1a", foreground: "#e2e8f0", accent: "#161928",
  sidebar: "#090c14", editor: "#0f1119", terminal: "#060810", statusBar: "#141726",
}, fontFamily: "DM Sans, sans-serif", fontSize: 14 };

const BUILT_IN_THEMES: readonly Theme[] = [T3_DARK, T3_LIGHT, T3_MIDNIGHT];

export function listThemes(): readonly Theme[] { return BUILT_IN_THEMES; }

export function getTheme(id: string): Theme | undefined {
  return BUILT_IN_THEMES.find((t) => t.id === id);
}
```

---

## Step 2 – `packages/shared/package.json` — add subpath export

Add after the `./Net` entry:

```json
"./themes": {
  "types": "./src/themes.ts",
  "import": "./src/themes.ts"
}
```

---

## Step 3 – `apps/web/src/hooks/useTheme.ts` (full replacement)

Preserve the `useSyncExternalStore` + module-level listener pattern already in use.

```ts
import { useCallback, useEffect, useSyncExternalStore } from "react";
import { DEFAULT_THEME_ID, type Theme, getTheme, listThemes } from "@t3tools/shared/themes";

const STORAGE_KEY = "t3code:theme";   // same key – old "light"/"dark"/"system" values fall back to default

let listeners: Array<() => void> = [];
function emitChange() { for (const l of listeners) l(); }

function getStoredId(): string {
  return localStorage.getItem(STORAGE_KEY) ?? DEFAULT_THEME_ID;
}

function getResolvedTheme(): Theme {
  return getTheme(getStoredId()) ?? getTheme(DEFAULT_THEME_ID)!;
}

function applyTheme(theme: Theme, suppressTransitions = false) {
  if (suppressTransitions) document.documentElement.classList.add("no-transitions");
  const { colors, fontFamily, fontSize } = theme;
  const root = document.documentElement;
  root.style.setProperty("--background", colors.background);
  root.style.setProperty("--foreground", colors.foreground);
  root.style.setProperty("--accent",     colors.accent);
  root.style.setProperty("--sidebar-bg", colors.sidebar);
  root.style.setProperty("--editor-bg",  colors.editor);
  root.style.setProperty("--terminal-bg",colors.terminal);
  root.style.setProperty("--status-bar-bg", colors.statusBar);
  root.style.setProperty("--font-sans",  fontFamily);
  root.style.setProperty("--base-font-size", `${fontSize}px`);
  document.documentElement.classList.toggle("dark", theme.colorScheme === "dark");
  if (suppressTransitions) {
    document.documentElement.offsetHeight;  // force reflow
    requestAnimationFrame(() => document.documentElement.classList.remove("no-transitions"));
  }
}

// Apply immediately on module load to prevent flash
applyTheme(getResolvedTheme());

let lastSnapshot: Theme | null = null;
function getSnapshot(): Theme {
  const t = getResolvedTheme();
  if (lastSnapshot && lastSnapshot.id === t.id) return lastSnapshot;
  lastSnapshot = t;
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) { applyTheme(getResolvedTheme(), true); emitChange(); }
  };
  window.addEventListener("storage", handleStorage);
  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useTheme() {
  const theme = useSyncExternalStore(subscribe, getSnapshot);
  const availableThemes = listThemes();
  const resolvedTheme: "light" | "dark" = theme.colorScheme;

  const setTheme = useCallback((id: string) => {
    const next = getTheme(id) ?? getTheme(DEFAULT_THEME_ID)!;
    localStorage.setItem(STORAGE_KEY, next.id);
    applyTheme(next, true);
    emitChange();
  }, []);

  useEffect(() => { applyTheme(theme); }, [theme]);

  return { theme, setTheme, availableThemes, resolvedTheme } as const;
}
```

**Backward compatibility:**
- `resolvedTheme: "light" | "dark"` is preserved → `ChatView`, `DiffPanel`, `ChatMarkdown`,
  `DiffWorkerPoolProvider` need no changes.
- The `dark` CSS class is still toggled → all Tailwind `dark:` utilities continue to work.
- Old stored string values ("light", "dark", "system") don't match any theme ID → silently fall back
  to `DEFAULT_THEME_ID` ("t3-dark").

---

## Step 4 – `apps/web/src/components/ThemeSelector.tsx` (new file)

Compact menu button placed in the sidebar footer. Uses existing `Menu*` primitives and `Button`.

```tsx
import { PaletteIcon } from "lucide-react";
import { useTheme } from "~/hooks/useTheme";
import { Button } from "~/components/ui/button";
import { Menu, MenuTrigger, MenuPopup, MenuCheckboxItem } from "~/components/ui/menu";
import type { ThemeColors } from "@t3tools/shared/themes";

function ThemeSwatches({ colors }: { colors: ThemeColors }) {
  return (
    <div className="flex gap-0.5">
      {[colors.background, colors.accent, colors.sidebar].map((color, i) => (
        <div key={i} className="h-3 w-3 rounded-full border border-border/40"
             style={{ backgroundColor: color }} />
      ))}
    </div>
  );
}

export function ThemeSelector() {
  const { theme, setTheme, availableThemes } = useTheme();
  return (
    <Menu>
      <MenuTrigger render={
        <Button variant="ghost" size="sm"
                className="w-full justify-start gap-2 px-2 text-xs text-muted-foreground hover:text-foreground">
          <PaletteIcon size={14} />
          <span>{theme.name}</span>
        </Button>
      } />
      <MenuPopup side="top" align="start">
        {availableThemes.map((t) => (
          <MenuCheckboxItem key={t.id} checked={t.id === theme.id}
                            onCheckedChange={() => setTheme(t.id)}>
            <div className="flex items-center gap-2">
              <ThemeSwatches colors={t.colors} />
              <span>{t.name}</span>
            </div>
          </MenuCheckboxItem>
        ))}
      </MenuPopup>
    </Menu>
  );
}
```

---

## Step 5 – `apps/web/src/routes/_chat.settings.tsx` (update Appearance section)

**Diffs:**

1. Remove the `THEME_OPTIONS` constant array (lines 25-41).

2. Update the destructure on the `useTheme()` call:
   ```ts
   // Before:
   const { theme, setTheme, resolvedTheme } = useTheme();
   // After:
   const { theme, setTheme, availableThemes } = useTheme();
   ```

3. Replace the `Appearance` section (lines 202–243). Key changes:
   - Map over `availableThemes` instead of `THEME_OPTIONS`
   - Selection check: `theme.id === t.id` (was `theme === option.value`)
   - Click handler: `setTheme(t.id)` (was `setTheme(option.value)`)
   - Add `ThemeSwatches` beside each label (import from `~/components/ThemeSelector`)  
   - Footer text: show `theme.name` (was `resolvedTheme`)
   - Update section description to say "Choose your colour theme."

---

## Step 6 – `apps/web/src/components/Sidebar.tsx` (wire ThemeSelector into footer)

1. Add import at top with other local component imports:
   ```ts
   import { ThemeSelector } from "./ThemeSelector";
   ```

2. In `SidebarFooter` (around line 1427), add `ThemeSelector` as a new `SidebarMenuItem`
   before the existing Settings/Back-to-Chat item:
   ```tsx
   <SidebarFooter className="p-2">
     <SidebarMenu>
       <SidebarMenuItem>
         <ThemeSelector />
       </SidebarMenuItem>
       <SidebarMenuItem>
         {/* existing settings button unchanged */}
       </SidebarMenuItem>
     </SidebarMenu>
   </SidebarFooter>
   ```

---

## Reused Patterns & Utilities

| Pattern | Source |
|---------|--------|
| `useSyncExternalStore` external store | `apps/web/src/hooks/useTheme.ts` (existing) |
| `no-transitions` suppression on theme change | `apps/web/src/hooks/useTheme.ts` (existing) |
| `localStorage` key prefixed `"t3code:"` | `apps/web/src/store.ts`, `appSettings.ts`, etc. |
| `Menu` / `MenuTrigger` / `MenuPopup` / `MenuCheckboxItem` | `apps/web/src/components/ui/menu.tsx` |
| `Button` variants | `apps/web/src/components/ui/button.tsx` |
| Subpath export pattern | `packages/shared/package.json` (all existing entries) |

---

## Verification

1. **Typecheck**: `bun typecheck` must pass across all packages (shared, web, server).
2. **Lint**: `bun lint` must pass.
3. **Visual**: Boot the web app (`bun dev`). The sidebar footer shows a palette button labelled "T3 Dark".
   Clicking it opens a menu with three theme options, each with three swatches. Selecting a theme
   immediately changes the UI colours (background, foreground, accent) and persists across page reloads.
4. **Settings page**: Navigate to Settings → Appearance. All three named themes are shown as radio
   buttons. Selecting one updates the whole UI. The footer shows the theme name.
5. **Backward compat**: Components that use `resolvedTheme` (`DiffPanel`, `ChatMarkdown`,
   `DiffWorkerPoolProvider`) continue to work unchanged because the new hook still exports
   `resolvedTheme: "light" | "dark"` derived from `theme.colorScheme`.
6. **Old localStorage values**: Clear storage or set `t3code:theme` to `"system"` manually —
   the app should silently fall back to `"t3-dark"` without errors.

