/**
 * Theme definitions for T3 Code.
 *
 * Each Theme captures the full set of CSS color tokens and typography
 * settings that the web app applies as inline CSS custom properties on
 * `document.documentElement` at runtime.
 */

export interface ThemeColors {
  /** Main page / panel background — applied to `--background`. */
  readonly background: string;
  /** Primary text — applied to `--foreground`. */
  readonly foreground: string;
  /** Subtle interactive background (hover states) — applied to `--accent`. */
  readonly accent: string;
  /** Sidebar surface — applied to `--sidebar-bg`. */
  readonly sidebar: string;
  /** Editor / code-view surface — applied to `--editor-bg`. */
  readonly editor: string;
  /** Terminal surface — applied to `--terminal-bg`. */
  readonly terminal: string;
  /** Status bar surface — applied to `--status-bar-bg`. */
  readonly statusBar: string;
}

export interface Theme {
  readonly id: string;
  readonly name: string;
  /** Determines whether the `dark` CSS class is applied to `<html>`. */
  readonly colorScheme: "light" | "dark";
  readonly colors: ThemeColors;
  /** CSS font-family value — applied to `--font-sans`. */
  readonly fontFamily: string;
  /** Base font size in px — applied to `--base-font-size`. */
  readonly fontSize: number;
}

// ---------------------------------------------------------------------------
// Built-in themes
// ---------------------------------------------------------------------------

/** Default: dark theme aligned with the existing Tailwind dark-mode palette. */
const T3_DARK: Theme = {
  id: "t3-dark",
  name: "T3 Dark",
  colorScheme: "dark",
  colors: {
    background: "#0a0a0a",
    foreground: "#f5f5f5",
    accent: "#171717",
    sidebar: "#111111",
    editor: "#141414",
    terminal: "#000000",
    statusBar: "#1a1a1a",
  },
  fontFamily: "DM Sans, sans-serif",
  fontSize: 14,
};

/** Light theme aligned with the existing Tailwind light-mode palette. */
const T3_LIGHT: Theme = {
  id: "t3-light",
  name: "T3 Light",
  colorScheme: "light",
  colors: {
    background: "#ffffff",
    foreground: "#262626",
    accent: "#f5f5f5",
    sidebar: "#f9fafb",
    editor: "#ffffff",
    terminal: "#1a1a1a",
    statusBar: "#e5e7eb",
  },
  fontFamily: "DM Sans, sans-serif",
  fontSize: 14,
};

/** Blue-tinted ultra-dark variant for late-night sessions. */
const T3_MIDNIGHT: Theme = {
  id: "t3-midnight",
  name: "T3 Midnight",
  colorScheme: "dark",
  colors: {
    background: "#0d0f1a",
    foreground: "#e2e8f0",
    accent: "#161928",
    sidebar: "#090c14",
    editor: "#0f1119",
    terminal: "#060810",
    statusBar: "#141726",
  },
  fontFamily: "DM Sans, sans-serif",
  fontSize: 14,
};

const BUILT_IN_THEMES: readonly Theme[] = [T3_DARK, T3_LIGHT, T3_MIDNIGHT];

/** The ID of the theme used when no valid stored preference is found. */
export const DEFAULT_THEME_ID = "t3-dark";

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

/** Returns all available themes in display order. */
export function listThemes(): readonly Theme[] {
  return BUILT_IN_THEMES;
}

/** Returns the theme with the given `id`, or `undefined` if not found. */
export function getTheme(id: string): Theme | undefined {
  return BUILT_IN_THEMES.find((t) => t.id === id);
}

