import { useCallback, useEffect, useSyncExternalStore } from "react";
import { DEFAULT_THEME_ID, type Theme, getTheme, listThemes } from "@t3tools/shared/themes";

const STORAGE_KEY = "t3code:theme";

// ---------------------------------------------------------------------------
// Module-level store (mirrors the pattern from the original useTheme)
// ---------------------------------------------------------------------------

let listeners: Array<() => void> = [];

function emitChange() {
  for (const listener of listeners) listener();
}

function getStoredId(): string {
  return localStorage.getItem(STORAGE_KEY) ?? DEFAULT_THEME_ID;
}

/**
 * Resolve the current theme from localStorage.
 * Falls back to the default when the stored value is missing or unrecognised
 * (including old "light" / "dark" / "system" values from the previous hook).
 */
function resolveStoredTheme(): Theme {
  return getTheme(getStoredId()) ?? (getTheme(DEFAULT_THEME_ID) as Theme);
}

function applyTheme(theme: Theme, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  const { colors, fontFamily, fontSize } = theme;
  const root = document.documentElement;

  // Core semantic colour tokens — these override the Tailwind @theme values
  // because inline element styles beat any stylesheet rule.
  root.style.setProperty("--background", colors.background);
  root.style.setProperty("--foreground", colors.foreground);
  root.style.setProperty("--accent", colors.accent);

  // App-specific surface tokens (new CSS variables consumed by theme-aware
  // components such as the terminal and editor panes).
  root.style.setProperty("--sidebar-bg", colors.sidebar);
  root.style.setProperty("--editor-bg", colors.editor);
  root.style.setProperty("--terminal-bg", colors.terminal);
  root.style.setProperty("--status-bar-bg", colors.statusBar);

  // Typography
  root.style.setProperty("--font-sans", fontFamily);
  root.style.setProperty("--base-font-size", `${fontSize}px`);

  // Toggle the Tailwind dark-mode class so that dark: utilities and
  // component-level dark variants keep working as before.
  document.documentElement.classList.toggle("dark", theme.colorScheme === "dark");

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal.
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent a flash of the wrong theme.
applyTheme(resolveStoredTheme());

// ---------------------------------------------------------------------------
// useSyncExternalStore plumbing
// ---------------------------------------------------------------------------

let lastSnapshot: Theme | null = null;

function getSnapshot(): Theme {
  const theme = resolveStoredTheme();
  // Preserve referential stability when nothing has changed.
  if (lastSnapshot !== null && lastSnapshot.id === theme.id) return lastSnapshot;
  lastSnapshot = theme;
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Sync theme changes that originate in other browser tabs.
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(resolveStoredTheme(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

// ---------------------------------------------------------------------------
// Public hook
// ---------------------------------------------------------------------------

export function useTheme() {
  const theme = useSyncExternalStore(subscribe, getSnapshot);
  const availableThemes = listThemes();

  /**
   * "light" | "dark" — preserved for backward-compatibility with components
   * that pass this value to diff renderers and markdown highlighters.
   */
  const resolvedTheme: "light" | "dark" = theme.colorScheme;

  const setTheme = useCallback((id: string) => {
    const next = getTheme(id) ?? (getTheme(DEFAULT_THEME_ID) as Theme);
    localStorage.setItem(STORAGE_KEY, next.id);
    applyTheme(next, true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount / hydration.
  useEffect(() => {
    applyTheme(theme);
  }, [theme]);

  return { theme, setTheme, availableThemes, resolvedTheme } as const;
}

