import { PaletteIcon } from "lucide-react";
import type { ThemeColors } from "@t3tools/shared/themes";

import { useTheme } from "~/hooks/useTheme";
import { Button } from "~/components/ui/button";
import { Menu, MenuItem, MenuPopup, MenuTrigger } from "~/components/ui/menu";

// ---------------------------------------------------------------------------
// Swatch preview
// ---------------------------------------------------------------------------

/**
 * Three small colour circles giving a quick visual preview of a theme's
 * background, accent, and sidebar surface colours.
 */
const SWATCH_KEYS = ["background", "accent", "sidebar"] as const;

function ThemeSwatches({ colors }: { colors: ThemeColors }) {
  return (
    <span className="flex shrink-0 gap-0.5" aria-hidden="true">
      {SWATCH_KEYS.map((key) => (
        <span
          key={key}
          className="inline-block size-3 rounded-full border border-border/40"
          style={{ backgroundColor: colors[key] }}
        />
      ))}
    </span>
  );
}

// ---------------------------------------------------------------------------
// Theme selector dropdown
// ---------------------------------------------------------------------------

/**
 * Compact palette-icon button that opens a dropdown listing every available
 * theme. Intended for placement in the sidebar footer.
 */
export function ThemeSelector() {
  const { theme, setTheme, availableThemes } = useTheme();

  return (
    <Menu>
      <MenuTrigger
        render={
          <Button
            variant="ghost"
            size="sm"
            aria-label="Select theme"
            className="w-full justify-start gap-2 px-2 text-xs text-muted-foreground hover:text-foreground"
          />
        }
      >
        <PaletteIcon className="size-3.5 shrink-0" />
        <span className="truncate">{theme.name}</span>
      </MenuTrigger>

      <MenuPopup side="top" align="start" className="w-48">
        {availableThemes.map((t) => (
          <MenuItem
            key={t.id}
            aria-current={t.id === theme.id ? "true" : undefined}
            className="gap-3"
            onClick={() => {
              setTheme(t.id);
            }}
          >
            <ThemeSwatches colors={t.colors} />
            <span className="flex-1 truncate">{t.name}</span>
            {t.id === theme.id && (
              <svg
                aria-hidden="true"
                className="size-3.5 shrink-0 text-primary"
                fill="none"
                stroke="currentColor"
                strokeLinecap="round"
                strokeLinejoin="round"
                strokeWidth={2.5}
                viewBox="0 0 24 24"
              >
                <path d="M5.252 12.7 10.2 18.63 18.748 5.37" />
              </svg>
            )}
          </MenuItem>
        ))}
      </MenuPopup>
    </Menu>
  );
}
